var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카일 웡이라...... 진짜 이름도 비슷하네요.","JPN":"カイル・ウォンか……本当に名前も似てるんですね。","ENG":"Kyle Wong. Even your name's similar.","TWN":"凱爾嗎……真的連名字也很像呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쯤 되면 무슨 운명의 장난 같은데?","JPN":"ここまでくると、何かの運命のイタズラみたいな？","ENG":"This has to be some sort of trick.","TWN":"這是什麼命運的玩笑嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭘 보고 계신 거죠?","JPN":"何を見ているんです？","ENG":"What are you looking at?","TWN":"妳在看什麼？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 카린 양. 카린 양의 이세계 오빠로 추정되는 분의 신분증을 살펴보고 있었어요.","JPN":"あ、カリンさん。カリンさんのお兄ちゃん風の方の身分証を見ていました。","ENG":"Oh, Karin. I was looking at the identification card of your otherworldly brother.","TWN":"啊，卡琳小姐。我看了下卡琳小姐異世界哥哥的身份證。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"놀라지 마시라, 짜잔! 이 분도 델타 세븐 소속이라고요!","JPN":"なんと、じゃじゃーん！　この方もデルタセブン所属なんです！","ENG":"Don't be surprised—tah-dah! Even he's in Delta Seven!","TWN":"請不要被嚇到哦，鏘鏘！這位也隸屬第七三角洲部隊！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이쪽 세계에도 델타 세븐이라는 부대가 있나 본데요?","JPN":"この世界にもデルタセブンという部隊があるようですよ？","ENG":"There must be a unit with that same name here, huh?","TWN":"看來這個世界也有叫作第七三角洲的部隊耶？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기 델타 세븐에는 누가 있는지 궁금하지 않아요?","JPN":"ここのデルタセブンにいるのは誰か、気になりませんか？","ENG":"Don't you want to know who might be in this Delta Seven?","TWN":"妳不好奇這邊的第七三角洲部隊裡有誰嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어쩌면 알만한 얼굴들이 더 있을 수도......","JPN":"もしかしたら、顔見知りが他にもいるかも……","ENG":"Perhaps there are more familiar faces.","TWN":"說不定會有更多熟悉的面孔……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......우연일 뿐이겠죠. 그런 쓸데없는 호기심을 충족할 여유는 없습니다.","JPN":"……偶然にすぎません。そんな無駄な好奇心に構っている暇はありません。","ENG":"This just has to be a coincidence. We don't have time to satisfy our personal curiosity.","TWN":"……應該只是偶然吧。現在可沒時間去滿足妳那沒用的好奇心。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨가 시간을 벌어준 덕분에 이 시설들의 통제권을 확보할 수 있었습니다.","JPN":"シノンさんが時間稼ぎしてくれたおかげで、この施設の統制権を確保できました。","ENG":"Shiyoung, because you stalled them, I was able to take control over these facilities.","TWN":"多虧周時雨小姐爭取了時間，我可以獲取這座設施的控制權了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"예측대로 이건 고도로 발전된 이터니움 반응로 같아요.","JPN":"予想通り、これは高度の発展を遂げたエタニウム反応炉のようです。","ENG":"This is just as I expected. I think it's a highly advanced Eternium reactor.","TWN":"不出所料，這是一個高度發達的永恆之金反應爐。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이터니움 반응로?","JPN":"エタニウム反応炉？","ENG":"An Eternium reactor?","TWN":"永恆之金反應爐？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 저희 델타 세븐에서도 구상 단계에 머물러 있던...... 이론상의 동력기관이죠.","JPN":"はい、我がデルタセブンでも構想レベルに留まっていた……理論上の動力機関なんです。","ENG":"Yes. It's a theoretical engine that my Delta Seven has only dreamed of.","TWN":"沒錯。我們第七三角洲部隊也只停留在構思階段……理論上這是一個動力機關。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 반응로를 다시 가동하면, 우리 세계와 이곳 간의 차원 통로를 확보할 수 있어요.","JPN":"要するに、反応炉を再稼働すれば、私たちの世界と、この世界との次元間通路を確保できます。","ENG":"If we reactivate this reactor, we can open up a passage between here and our world.","TWN":"所以只要重新啟動反應爐，就可以確保我們的世界和這裡之間的次元通道。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와, 그거 참 좋은 소식이네요.","JPN":"おお、それは嬉しいニュースですね。","ENG":"Wow, that's great news!","TWN":"哇喔，那可真是個好消息呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"원래는 에너지원으로 쓸 고순도 이터니움을 현지 조달한다는 황당한 계획이었는데 말이죠.","JPN":"元々はエネルギー原として使うための高純度エタニウムを現地調達するという、とんでもない計画だったのに。","ENG":"Our original plan was a reckless one, to self-supply high-purity Eternium for energy generation purposes.","TWN":"不過，高純度永恆之金原來是作為能量源使用的，他們竟然現場調配，真是個荒唐的計畫呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이걸로 생환 가능성이 5% 정도는 올랐겠죠?","JPN":"これで生きて帰れる可能性が5％くらいは上がったでしょうか？","ENG":"This should have increased our chances of survival by 5%, right?","TWN":"這下我們生還的可能性應該上升了5%左右吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋은 소식......","JPN":"嬉しいニュース……","ENG":"Great news...","TWN":"好消息……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};